{
  "name": "MacTools Pro",
  "description": "A macOS-inspired productivity utility for developers featuring timestamp conversion, base conversion, and integrated web tool management.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface WebTool {
  id: string;
  name: string;
  url: string;
  icon: string;
}

export enum ToolView {
  DASHBOARD = 'DASHBOARD',
  TIMESTAMP = 'TIMESTAMP',
  BASE_CONVERTER = 'BASE_CONVERTER',
  WEB_TOOLS = 'WEB_TOOLS',
  SETTINGS = 'SETTINGS'
}

import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import TimestampConverter from './components/TimestampConverter';
import BaseConverter from './components/BaseConverter';
import WebToolManager from './components/WebToolManager';
import CommandPalette from './components/CommandPalette';
import { ToolView, WebTool } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ToolView>(ToolView.DASHBOARD);
  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
  const [selectedWebTool, setSelectedWebTool] = useState<WebTool | null>(null);

  // Load web tools from storage
  const [webTools, setWebTools] = useState<WebTool[]>(() => {
    const saved = localStorage.getItem('mac_web_tools');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Google', url: 'https://www.google.com/search?igu=1', icon: '🔍' },
      { id: '2', name: 'GitHub', url: 'https://github.com', icon: '🐙' }
    ];
  });

  useEffect(() => {
    localStorage.setItem('mac_web_tools', JSON.stringify(webTools));
  }, [webTools]);

  const toggleCommandPalette = useCallback(() => {
    setIsCommandPaletteOpen(prev => !prev);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Simulate Mac shortcut Cmd + K (or Ctrl + K)
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        toggleCommandPalette();
      }
      // Escape to close
      if (e.key === 'Escape') {
        setIsCommandPaletteOpen(false);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [toggleCommandPalette]);

  const renderView = () => {
    switch (activeView) {
      case ToolView.TIMESTAMP:
        return <TimestampConverter />;
      case ToolView.BASE_CONVERTER:
        return <BaseConverter />;
      case ToolView.WEB_TOOLS:
        return (
          <WebToolManager 
            webTools={webTools} 
            setWebTools={setWebTools} 
            onSelectTool={(tool) => {
              setSelectedWebTool(tool);
              setActiveView(ToolView.WEB_TOOLS);
            }}
          />
        );
      case ToolView.DASHBOARD:
      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-white/80 p-12">
            <h1 className="text-4xl font-bold mb-4">Welcome to MacTools</h1>
            <p className="text-lg opacity-60 mb-8">Press <kbd className="bg-white/10 px-2 py-1 rounded">⌘K</kbd> to open command palette</p>
            <div className="grid grid-cols-2 gap-4 w-full max-w-lg">
              <button 
                onClick={() => setActiveView(ToolView.TIMESTAMP)}
                className="p-6 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl transition-all text-left"
              >
                <div className="text-2xl mb-2">🕒</div>
                <div className="font-semibold">Timestamp</div>
                <div className="text-sm opacity-50">Convert unix time to dates</div>
              </button>
              <button 
                onClick={() => setActiveView(ToolView.BASE_CONVERTER)}
                className="p-6 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl transition-all text-left"
              >
                <div className="text-2xl mb-2">🔢</div>
                <div className="font-semibold">Base Converter</div>
                <div className="text-sm opacity-50">Bin, Oct, Dec, Hex & more</div>
              </button>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950">
      {/* Sidebar */}
      <Sidebar activeView={activeView} setActiveView={setActiveView} />

      {/* Main Content Area */}
      <main className="flex-1 overflow-auto relative mac-blur bg-black/20">
        {activeView === ToolView.WEB_TOOLS && selectedWebTool ? (
          <div className="h-full w-full flex flex-col">
            <div className="h-10 bg-black/40 border-b border-white/10 flex items-center px-4 justify-between">
               <div className="flex items-center space-x-2">
                 <span className="text-sm font-medium text-white/80">{selectedWebTool.name}</span>
                 <span className="text-xs text-white/40">{selectedWebTool.url}</span>
               </div>
               <button 
                onClick={() => setSelectedWebTool(null)}
                className="text-white/40 hover:text-white/100 text-xs"
               >
                 Exit Tool
               </button>
            </div>
            <iframe 
              src={selectedWebTool.url} 
              className="flex-1 w-full border-none"
              title={selectedWebTool.name}
              sandbox="allow-same-origin allow-scripts allow-popups allow-forms"
            />
          </div>
        ) : (
          renderView()
        )}
      </main>

      {/* Overlays */}
      <CommandPalette 
        isOpen={isCommandPaletteOpen} 
        onClose={() => setIsCommandPaletteOpen(false)} 
        onSelect={(view) => {
          setActiveView(view);
          setIsCommandPaletteOpen(false);
          setSelectedWebTool(null);
        }}
      />
    </div>
  );
};

export default App;

import React from 'react';
import { ToolView } from '../types';

interface SidebarProps {
  activeView: ToolView;
  setActiveView: (view: ToolView) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeView, setActiveView }) => {
  const items = [
    { view: ToolView.DASHBOARD, label: 'Dashboard', icon: '🏠' },
    { view: ToolView.TIMESTAMP, label: 'Timestamp', icon: '🕒' },
    { view: ToolView.BASE_CONVERTER, label: 'Base Conv', icon: '🔢' },
    { view: ToolView.WEB_TOOLS, label: 'Web Tools', icon: '🌐' },
  ];

  return (
    <aside className="w-64 bg-black/40 border-r border-white/10 flex flex-col p-4">
      <div className="flex items-center space-x-2 px-2 mb-8">
        <div className="flex space-x-1.5">
          <div className="w-3 h-3 rounded-full bg-red-500" />
          <div className="w-3 h-3 rounded-full bg-yellow-500" />
          <div className="w-3 h-3 rounded-full bg-green-500" />
        </div>
        <span className="text-white/60 font-bold ml-4 tracking-tight">MacTools Pro</span>
      </div>

      <nav className="flex-1 space-y-1">
        {items.map((item) => (
          <button
            key={item.view}
            onClick={() => setActiveView(item.view)}
            className={`w-full flex items-center space-x-3 px-3 py-2 rounded-lg transition-all ${
              activeView === item.view 
                ? 'bg-white/15 text-white shadow-lg' 
                : 'text-white/60 hover:bg-white/5 hover:text-white/80'
            }`}
          >
            <span className="text-xl">{item.icon}</span>
            <span className="font-medium">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="mt-auto pt-4 border-t border-white/10">
        <div className="px-3 py-2 text-xs text-white/30 uppercase tracking-widest font-bold">
          System info
        </div>
        <div className="px-3 py-2 text-white/50 text-xs">
          v1.0.0 Stable
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';

const TimestampConverter: React.FC = () => {
  const [input, setInput] = useState<string>(Math.floor(Date.now() / 1000).toString());
  const [unit, setUnit] = useState<'s' | 'ms'>('s');

  const getFormattedDate = (val: string) => {
    try {
      const num = parseInt(val);
      if (isNaN(num)) return null;
      const date = new Date(unit === 's' ? num * 1000 : num);
      if (isNaN(date.getTime())) return null;
      return date;
    } catch {
      return null;
    }
  };

  const date = getFormattedDate(input);

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('Copied to clipboard!');
  };

  return (
    <div className="p-8 max-w-4xl mx-auto text-white">
      <h2 className="text-2xl font-bold mb-6 flex items-center">
        <span className="mr-2">🕒</span> Timestamp Converter
      </h2>

      <div className="bg-white/5 border border-white/10 rounded-2xl p-6 mb-8">
        <div className="flex flex-col space-y-4">
          <label className="text-sm font-medium text-white/50 uppercase tracking-wider">
            Enter Unix Timestamp
          </label>
          <div className="flex space-x-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              className="flex-1 bg-black/30 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500 text-xl font-mono"
              placeholder="e.g. 1672531200"
            />
            <select
              value={unit}
              onChange={(e) => setUnit(e.target.value as 's' | 'ms')}
              className="bg-black/30 border border-white/10 rounded-xl px-4 py-3 focus:outline-none"
            >
              <option value="s">Seconds (s)</option>
              <option value="ms">Milliseconds (ms)</option>
            </select>
            <button 
              onClick={() => setInput(unit === 's' ? Math.floor(Date.now()/1000).toString() : Date.now().toString())}
              className="px-4 py-3 bg-blue-600 hover:bg-blue-500 rounded-xl transition-colors font-medium"
            >
              Now
            </button>
          </div>
        </div>
      </div>

      {date ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {[
            { label: 'Local Time', value: date.toLocaleString() },
            { label: 'ISO 8601', value: date.toISOString() },
            { label: 'UTC Time', value: date.toUTCString() },
            { label: 'Date String', value: date.toDateString() },
            { label: 'Time String', value: date.toTimeString() },
            { label: 'Unix (Seconds)', value: Math.floor(date.getTime() / 1000).toString() }
          ].map((item, idx) => (
            <div key={idx} className="bg-white/5 border border-white/10 rounded-xl p-4 flex flex-col justify-between group">
              <span className="text-xs text-white/40 mb-1">{item.label}</span>
              <div className="flex items-center justify-between">
                <span className="font-mono text-sm break-all">{item.value}</span>
                <button 
                  onClick={() => copyToClipboard(item.value)}
                  className="opacity-0 group-hover:opacity-100 transition-opacity p-2 hover:bg-white/10 rounded-lg"
                >
                  📋
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center p-12 bg-white/5 border border-dashed border-white/20 rounded-2xl text-white/40">
          Invalid timestamp format. Please check your input.
        </div>
      )}
    </div>
  );
};

export default TimestampConverter;

import React, { useState } from 'react';

const BaseConverter: React.FC = () => {
  const [value, setValue] = useState('255');
  const [fromBase, setFromBase] = useState(10);

  const bases = [
    { name: 'Binary', value: 2 },
    { name: 'Octal', value: 8 },
    { name: 'Decimal', value: 10 },
    { name: 'Hexadecimal', value: 16 },
    { name: 'Base 32', value: 32 },
    { name: 'Base 36', value: 36 },
  ];

  const getConversions = () => {
    try {
      const decimal = parseInt(value, fromBase);
      if (isNaN(decimal)) return [];

      return bases.map(b => ({
        ...b,
        result: decimal.toString(b.value).toUpperCase()
      }));
    } catch {
      return [];
    }
  };

  const results = getConversions();

  return (
    <div className="p-8 max-w-4xl mx-auto text-white">
      <h2 className="text-2xl font-bold mb-6 flex items-center">
        <span className="mr-2">🔢</span> Base Converter
      </h2>

      <div className="bg-white/5 border border-white/10 rounded-2xl p-6 mb-8 flex flex-col space-y-4">
        <div className="flex flex-col space-y-2">
          <label className="text-xs font-medium text-white/40 uppercase">Input Value</label>
          <div className="flex space-x-2">
             <input
              type="text"
              value={value}
              onChange={(e) => setValue(e.target.value)}
              className="flex-1 bg-black/30 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-purple-500 font-mono text-xl"
              placeholder="Enter value..."
            />
            <select
              value={fromBase}
              onChange={(e) => setFromBase(parseInt(e.target.value))}
              className="bg-black/30 border border-white/10 rounded-xl px-4 py-3 focus:outline-none"
            >
              {bases.map(b => (
                <option key={b.value} value={b.value}>{b.name}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {results.length > 0 ? results.map((res) => (
          <div key={res.value} className="bg-white/5 border border-white/10 rounded-xl p-5 flex flex-col group hover:bg-white/10 transition-colors">
            <div className="flex items-center justify-between mb-2">
               <span className="text-sm font-semibold text-purple-400">{res.name} (Base {res.value})</span>
               <button 
                 onClick={() => navigator.clipboard.writeText(res.result)}
                 className="opacity-0 group-hover:opacity-100 p-1 hover:bg-white/10 rounded"
               >
                 📋
               </button>
            </div>
            <div className="font-mono text-lg break-all">{res.result}</div>
          </div>
        )) : (
          <div className="col-span-2 text-center py-12 text-white/30 italic">
            Enter a valid number to see conversions
          </div>
        )}
      </div>
    </div>
  );
};

export default BaseConverter;

import React, { useState } from 'react';
import { WebTool } from '../types';

interface WebToolManagerProps {
  webTools: WebTool[];
  setWebTools: React.Dispatch<React.SetStateAction<WebTool[]>>;
  onSelectTool: (tool: WebTool) => void;
}

const WebToolManager: React.FC<WebToolManagerProps> = ({ webTools, setWebTools, onSelectTool }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newTool, setNewTool] = useState({ name: '', url: '', icon: '🔗' });

  const addTool = () => {
    if (!newTool.name || !newTool.url) return;
    const tool: WebTool = {
      ...newTool,
      id: Date.now().toString()
    };
    setWebTools([...webTools, tool]);
    setNewTool({ name: '', url: '', icon: '🔗' });
    setIsAdding(false);
  };

  const removeTool = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setWebTools(webTools.filter(t => t.id !== id));
  };

  return (
    <div className="p-8 max-w-5xl mx-auto text-white">
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-2xl font-bold flex items-center">
          <span className="mr-2">🌐</span> Integrated Web Tools
        </h2>
        <button 
          onClick={() => setIsAdding(true)}
          className="px-4 py-2 bg-green-600 hover:bg-green-500 rounded-lg transition-colors font-medium text-sm"
        >
          + Add New Tool
        </button>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {webTools.map((tool) => (
          <div 
            key={tool.id}
            onClick={() => onSelectTool(tool)}
            className="group relative bg-white/5 border border-white/10 rounded-2xl p-6 cursor-pointer hover:bg-white/10 hover:scale-[1.02] transition-all"
          >
            <button 
              onClick={(e) => removeTool(tool.id, e)}
              className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 text-red-400 hover:text-red-300 transition-opacity"
            >
              ✕
            </button>
            <div className="text-4xl mb-4">{tool.icon}</div>
            <div className="font-bold text-lg mb-1 truncate">{tool.name}</div>
            <div className="text-xs text-white/40 truncate">{tool.url}</div>
          </div>
        ))}

        {webTools.length === 0 && !isAdding && (
          <div className="col-span-full text-center py-24 bg-white/5 rounded-2xl border-2 border-dashed border-white/10">
            <div className="text-white/20 text-5xl mb-4">📭</div>
            <div className="text-white/40">No web tools added yet. Click "Add New Tool" to start.</div>
          </div>
        )}
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-slate-900 border border-white/10 rounded-3xl p-8 w-full max-w-md shadow-2xl">
            <h3 className="text-xl font-bold mb-6">Add Web Tool</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-semibold text-white/40 uppercase mb-1">Tool Name</label>
                <input 
                  type="text" 
                  value={newTool.name}
                  onChange={(e) => setNewTool({...newTool, name: e.target.value})}
                  className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-2 focus:ring-2 focus:ring-green-500 outline-none"
                  placeholder="e.g. StackOverflow"
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-white/40 uppercase mb-1">URL (Must support iframe)</label>
                <input 
                  type="text" 
                  value={newTool.url}
                  onChange={(e) => setNewTool({...newTool, url: e.target.value})}
                  className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-2 focus:ring-2 focus:ring-green-500 outline-none"
                  placeholder="https://..."
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-white/40 uppercase mb-1">Icon Emoji</label>
                <input 
                  type="text" 
                  value={newTool.icon}
                  onChange={(e) => setNewTool({...newTool, icon: e.target.value})}
                  className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-2 focus:ring-2 focus:ring-green-500 outline-none"
                  placeholder="🚀"
                />
              </div>
              <p className="text-[10px] text-yellow-400/60 mt-2">
                Note: Many major websites (Google, GitHub, etc.) block embedding in iframes for security reasons. Try tools designed for developers or internal dashboard URLs.
              </p>
              <div className="flex space-x-3 mt-8">
                <button 
                  onClick={() => setIsAdding(false)}
                  className="flex-1 px-4 py-2 bg-white/5 hover:bg-white/10 rounded-xl transition-colors"
                >
                  Cancel
                </button>
                <button 
                  onClick={addTool}
                  className="flex-1 px-4 py-2 bg-green-600 hover:bg-green-500 rounded-xl transition-colors font-bold"
                >
                  Save Tool
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default WebToolManager;

import React, { useState, useEffect, useRef } from 'react';
import { ToolView } from '../types';

interface CommandPaletteProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (view: ToolView) => void;
}

const CommandPalette: React.FC<CommandPaletteProps> = ({ isOpen, onClose, onSelect }) => {
  const [query, setQuery] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  const commands = [
    { id: ToolView.DASHBOARD, name: 'Home / Dashboard', icon: '🏠', shortcut: 'H' },
    { id: ToolView.TIMESTAMP, name: 'Timestamp Converter', icon: '🕒', shortcut: 'T' },
    { id: ToolView.BASE_CONVERTER, name: 'Base Converter (Hex/Bin)', icon: '🔢', shortcut: 'B' },
    { id: ToolView.WEB_TOOLS, name: 'Manage Web Tools', icon: '🌐', shortcut: 'W' },
  ];

  const filteredCommands = commands.filter(c => 
    c.name.toLowerCase().includes(query.toLowerCase())
  );

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 50);
    } else {
      setQuery('');
    }
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center pt-[15vh] px-4 bg-black/20 backdrop-blur-sm" onClick={onClose}>
      <div 
        className="w-full max-w-xl bg-slate-900/90 border border-white/20 rounded-2xl shadow-2xl overflow-hidden flex flex-col"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="p-4 border-b border-white/10 flex items-center space-x-3 bg-black/20">
          <span className="text-2xl">🔍</span>
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Type a command or search..."
            className="flex-1 bg-transparent border-none outline-none text-white text-lg placeholder-white/30"
          />
          <div className="px-2 py-1 rounded bg-white/5 border border-white/10 text-[10px] text-white/40 font-mono">
            ESC to close
          </div>
        </div>

        <div className="max-h-[60vh] overflow-auto p-2">
          {filteredCommands.length > 0 ? (
            filteredCommands.map((cmd) => (
              <button
                key={cmd.id}
                onClick={() => onSelect(cmd.id)}
                className="w-full flex items-center justify-between p-3 rounded-xl hover:bg-white/10 transition-colors text-left group"
              >
                <div className="flex items-center space-x-3">
                  <span className="text-xl group-hover:scale-110 transition-transform">{cmd.icon}</span>
                  <span className="text-white/80 font-medium">{cmd.name}</span>
                </div>
                <div className="text-xs text-white/20 font-mono px-2 py-1 rounded border border-white/5 group-hover:border-white/20">
                  {cmd.shortcut}
                </div>
              </button>
            ))
          ) : (
            <div className="p-12 text-center text-white/30 italic">
              No commands matching "{query}"
            </div>
          )}
        </div>

        <div className="p-3 bg-black/40 border-t border-white/10 flex items-center justify-between">
           <div className="flex space-x-4">
              <span className="text-[10px] text-white/30 flex items-center">
                <kbd className="bg-white/10 px-1 rounded mr-1">↑↓</kbd> to navigate
              </span>
              <span className="text-[10px] text-white/30 flex items-center">
                <kbd className="bg-white/10 px-1 rounded mr-1">↵</kbd> to select
              </span>
           </div>
           <span className="text-[10px] text-white/20">MacTools Assistant</span>
        </div>
      </div>
    </div>
  );
};

export default CommandPalette;

export interface WebTool {
  id: string;
  name: string;
  url: string;
  icon: string;
}

export enum ToolView {
  DASHBOARD = 'DASHBOARD',
  TIMESTAMP = 'TIMESTAMP',
  BASE_CONVERTER = 'BASE_CONVERTER',
  WEB_TOOLS = 'WEB_TOOLS',
  CALCULATOR = 'CALCULATOR',
  SETTINGS = 'SETTINGS'
}

import React, { useState, useEffect, useCallback } from 'react';

const Calculator: React.FC = () => {
  const [display, setDisplay] = useState('0');
  const [equation, setEquation] = useState('');
  const [history, setHistory] = useState<string[]>([]);
  const [shouldReset, setShouldReset] = useState(false);

  const calculate = useCallback(() => {
    try {
      // Basic safety check for eval-like behavior
      const sanitized = equation.replace(/[^-()\d/*+.]/g, '');
      const result = Function(`'use strict'; return (${sanitized})`)();
      const resultStr = Number.isInteger(result) ? result.toString() : result.toFixed(4).replace(/\.?0+$/, "");

      setHistory(prev => [`${equation} = ${resultStr}`, ...prev].slice(0, 10));
      setDisplay(resultStr);
      setEquation(resultStr);
      setShouldReset(true);
    } catch (e) {
      setDisplay('Error');
      setShouldReset(true);
    }
  }, [equation]);

  const handleInput = useCallback((value: string) => {
    if (value === 'AC') {
      setDisplay('0');
      setEquation('');
      setShouldReset(false);
      return;
    }

    if (value === '=') {
      calculate();
      return;
    }

    if (value === '±') {
      setDisplay(prev => (parseFloat(prev) * -1).toString());
      setEquation(prev => (parseFloat(prev) * -1).toString());
      return;
    }

    if (value === '%') {
      const val = (parseFloat(display) / 100).toString();
      setDisplay(val);
      setEquation(val);
      return;
    }

    // Handle numbers and operators
    if (shouldReset && !['+', '-', '*', '/'].includes(value)) {
      setDisplay(value);
      setEquation(value);
      setShouldReset(false);
    } else {
      setShouldReset(false);
      const isOperator = ['+', '-', '*', '/'].includes(value);

      if (display === '0' && !isOperator) {
        setDisplay(value);
        setEquation(value);
      } else {
        setDisplay(prev => isOperator ? prev : (shouldReset ? value : prev + value));
        setEquation(prev => prev + value);
      }
    }
  }, [calculate, display, shouldReset]);

  // Keyboard support
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key >= '0' && e.key <= '9') handleInput(e.key);
      if (e.key === '.') handleInput('.');
      if (e.key === '+') handleInput('+');
      if (e.key === '-') handleInput('-');
      if (e.key === '*') handleInput('*');
      if (e.key === '/') handleInput('/');
      if (e.key === 'Enter' || e.key === '=') handleInput('=');
      if (e.key === 'Escape' || e.key === 'c') handleInput('AC');
      if (e.key === 'Backspace') {
        setDisplay(prev => prev.length > 1 ? prev.slice(0, -1) : '0');
        setEquation(prev => prev.length > 1 ? prev.slice(0, -1) : '');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleInput]);

  const buttons = [
    { label: 'AC', className: 'bg-zinc-400 text-black hover:bg-zinc-300' },
    { label: '±', className: 'bg-zinc-400 text-black hover:bg-zinc-300' },
    { label: '%', className: 'bg-zinc-400 text-black hover:bg-zinc-300' },
    { label: '/', className: 'bg-orange-500 text-white hover:bg-orange-400', value: '/' },
    { label: '7', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '8', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '9', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '×', className: 'bg-orange-500 text-white hover:bg-orange-400', value: '*' },
    { label: '4', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '5', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '6', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '−', className: 'bg-orange-500 text-white hover:bg-orange-400', value: '-' },
    { label: '1', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '2', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '3', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '+', className: 'bg-orange-500 text-white hover:bg-orange-400', value: '+' },
    { label: '0', className: 'bg-zinc-700 text-white hover:bg-zinc-600 col-span-2 text-left px-8' },
    { label: '.', className: 'bg-zinc-700 text-white hover:bg-zinc-600' },
    { label: '=', className: 'bg-orange-500 text-white hover:bg-orange-400' },
  ];

  return (
    <div className="p-8 max-w-4xl mx-auto flex flex-col md:flex-row gap-8 items-start">
      <div className="flex-1">
        <h2 className="text-2xl font-bold mb-6 text-white flex items-center">
          <span className="mr-2">🧮</span> Calculator
        </h2>

        <div className="bg-black/60 rounded-[30px] p-4 shadow-2xl border border-white/10 w-[320px]">
          <div className="h-24 flex flex-col justify-end items-end px-4 mb-4">
             <div className="text-white/40 text-sm font-mono truncate max-w-full">{equation || ' '}</div>
             <div className="text-white text-5xl font-light tracking-tight truncate max-w-full">
               {display}
             </div>
          </div>

          <div className="grid grid-cols-4 gap-3">
            {buttons.map((btn, idx) => (
              <button
                key={idx}
                onClick={() => handleInput(btn.value || btn.label)}
                className={`${btn.className} h-14 rounded-full flex items-center justify-center text-xl font-medium transition-all active:scale-95 ${btn.colSpan ? 'col-span-2' : ''} ${btn.label === '0' ? 'col-span-2 aspect-auto' : 'aspect-square'}`}
              >
                {btn.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="w-full md:w-64 bg-white/5 border border-white/10 rounded-2xl p-6 self-stretch">
        <h3 className="text-sm font-bold text-white/40 uppercase tracking-widest mb-4">History</h3>
        <div className="space-y-3">
          {history.length > 0 ? history.map((item, i) => (
            <div key={i} className="text-sm font-mono text-white/70 border-b border-white/5 pb-2">
