import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import TimestampConverter from './components/TimestampConverter';
import BaseConverter from './components/BaseConverter';
import WebToolManager from './components/WebToolManager';
import Calculator from './components/Calculator';
import CommandPalette from './components/CommandPalette';
import Settings from './components/Settings';
import { ToolView, WebTool } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ToolView>(ToolView.DASHBOARD);
  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
  const [selectedWebTool, setSelectedWebTool] = useState<WebTool | null>(null);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isInstalled, setIsInstalled] = useState(false);
  const [iframeLoading, setIframeLoading] = useState(true);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const [webTools, setWebTools] = useState<WebTool[]>(() => {
    const saved = localStorage.getItem('mac_web_tools');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Google (Search Only)', url: 'https://www.google.com/search?igu=1', icon: '🔍' },
      { id: '2', name: 'GitHub', url: 'https://github.com', icon: '🐙' }
    ];
  });

  useEffect(() => {
    localStorage.setItem('mac_web_tools', JSON.stringify(webTools));
  }, [webTools]);

  // PWA Install Logic
  useEffect(() => {
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };

    const handleAppInstalled = () => {
      setIsInstalled(true);
      setDeferredPrompt(null);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    window.addEventListener('appinstalled', handleAppInstalled);

    if (window.matchMedia('(display-mode: standalone)').matches) {
      setIsInstalled(true);
    }

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
      window.removeEventListener('appinstalled', handleAppInstalled);
    };
  }, []);

  const installPWA = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') {
      setDeferredPrompt(null);
    }
  };

  const toggleCommandPalette = useCallback(() => {
    setIsCommandPaletteOpen(prev => !prev);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        toggleCommandPalette();
      }
      if (e.key === 'Escape') {
        setIsCommandPaletteOpen(false);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [toggleCommandPalette]);

  const refreshIframe = () => {
    if (iframeRef.current) {
      setIframeLoading(true);
      const currentSrc = iframeRef.current.src;
      iframeRef.current.src = '';
      setTimeout(() => {
        if (iframeRef.current) iframeRef.current.src = currentSrc;
      }, 10);
    }
  };

  const openExternally = () => {
    if (selectedWebTool) {
      window.open(selectedWebTool.url, '_blank');
    }
  };

  const renderView = () => {
    switch (activeView) {
      case ToolView.TIMESTAMP: return <TimestampConverter />;
      case ToolView.BASE_CONVERTER: return <BaseConverter />;
      case ToolView.CALCULATOR: return <Calculator />;
      case ToolView.SETTINGS: 
        return <Settings 
          onInstall={installPWA} 
          isInstallable={!!deferredPrompt} 
          isInstalled={isInstalled} 
        />;
      case ToolView.WEB_TOOLS:
        return (
          <WebToolManager 
            webTools={webTools} 
            setWebTools={setWebTools} 
            onSelectTool={(tool) => {
              setSelectedWebTool(tool);
              setIframeLoading(true);
              setActiveView(ToolView.WEB_TOOLS);
            }}
          />
        );
      case ToolView.DASHBOARD:
      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-white/80 p-12">
            <h1 className="text-4xl font-bold mb-4">Welcome to MacTools</h1>
            <p className="text-lg opacity-60 mb-8">Press <kbd className="bg-white/10 px-2 py-1 rounded">⌘K</kbd> to open command palette</p>

            {deferredPrompt && !isInstalled && (
              <button 
                onClick={installPWA}
                className="mb-10 px-6 py-3 bg-indigo-600 hover:bg-indigo-500 rounded-full font-bold shadow-xl shadow-indigo-900/40 transition-all flex items-center space-x-2 animate-bounce"
              >
                <span>📥</span>
                <span>Install to Desktop</span>
              </button>
            )}

            <div className="grid grid-cols-2 gap-4 w-full max-w-2xl">
              {[
                { view: ToolView.CALCULATOR, icon: '🧮', label: 'Calculator', sub: 'Math & History' },
                { view: ToolView.TIMESTAMP, icon: '🕒', label: 'Timestamp', sub: 'Unix converter' },
                { view: ToolView.BASE_CONVERTER, icon: '🔢', label: 'Base Converter', sub: 'Hex/Bin/Oct' },
                { view: ToolView.WEB_TOOLS, icon: '🌐', label: 'Web Tools', sub: 'Embedded apps' }
              ].map(card => (
                <button 
                  key={card.view}
                  onClick={() => setActiveView(card.view)}
                  className="p-6 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl transition-all text-left group"
                >
                  <div className="text-2xl mb-2 group-hover:scale-110 transition-transform">{card.icon}</div>
                  <div className="font-semibold">{card.label}</div>
                  <div className="text-sm opacity-50">{card.sub}</div>
                </button>
              ))}
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950">
      <Sidebar activeView={activeView} setActiveView={setActiveView} />

      <main className="flex-1 overflow-auto relative mac-blur bg-black/20 flex flex-col">
        <div className="window-drag-handle shrink-0" />

        <div className="flex-1 overflow-auto">
          {activeView === ToolView.WEB_TOOLS && selectedWebTool ? (
            <div className="h-full w-full flex flex-col">
              <div className="h-12 bg-black/60 border-b border-white/10 flex items-center px-4 justify-between">
                <div className="flex items-center space-x-4 overflow-hidden">
                  <div className="flex items-center space-x-2">
                      <span className="text-lg">{selectedWebTool.icon}</span>
                      <span className="text-sm font-bold text-white/80 truncate">{selectedWebTool.name}</span>
                  </div>
                  <div className="flex items-center space-x-1 border-l border-white/10 pl-4">
                      <button onClick={refreshIframe} className="p-1.5 hover:bg-white/10 rounded-lg text-white/40 hover:text-white transition-colors" title="Refresh">🔄</button>
                      <button onClick={openExternally} className="p-1.5 hover:bg-white/10 rounded-lg text-white/40 hover:text-white transition-colors flex items-center space-x-1" title="Open in browser">
                        <span className="text-xs font-medium">Open Externally</span>
                        <span>↗️</span>
                      </button>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                    <div className="hidden md:flex flex-col items-end mr-2">
                      <span className="text-[9px] text-white/30 uppercase font-bold leading-none">Status</span>
                      <span className={`text-[10px] ${iframeLoading ? 'text-yellow-500' : 'text-green-500'} font-mono`}>
                        ● {iframeLoading ? 'LOADING' : 'READY'}
                      </span>
                    </div>
                    <button onClick={() => setSelectedWebTool(null)} className="px-3 py-1 bg-white/5 hover:bg-white/15 rounded-md text-white/60 text-xs transition-colors border border-white/10">Close</button>
                </div>
              </div>
              <div className="flex-1 relative bg-slate-900">
                {iframeLoading && (
                  <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-slate-900 text-white/40 space-y-4">
                    <div className="w-10 h-10 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
                    <div className="text-center">
                      <p className="text-sm font-medium">Loading Tool...</p>
                      <p className="text-[10px] mt-2 max-w-xs opacity-60">If this takes too long, the site might be blocking iframe access (X-Frame-Options).</p>
                    </div>
                  </div>
                )}
                <iframe 
                  ref={iframeRef} 
                  src={selectedWebTool.url} 
                  onLoad={() => setIframeLoading(false)}
                  className="absolute inset-0 w-full h-full border-none" 
                  sandbox="allow-same-origin allow-scripts allow-popups allow-forms allow-modals allow-downloads allow-popups-to-escape-sandbox" 
                />
              </div>
            </div>
          ) : (
            renderView()
          )}
        </div>
      </main>

      <CommandPalette 
        isOpen={isCommandPaletteOpen} 
        onClose={() => setIsCommandPaletteOpen(false)} 
        onSelect={(view) => {
          setActiveView(view);
          setIsCommandPaletteOpen(false);
          setSelectedWebTool(null);
        }}
      />
    </div>
  );
};

export default App;

export interface WebTool {
  id: string;
  name: string;
  url: string;
  icon: string;
  openMode?: 'iframe' | 'window';
}

export enum ToolView {
  DASHBOARD = 'DASHBOARD',
  TIMESTAMP = 'TIMESTAMP',
  BASE_CONVERTER = 'BASE_CONVERTER',
  WEB_TOOLS = 'WEB_TOOLS',
  CALCULATOR = 'CALCULATOR',
  SETTINGS = 'SETTINGS'
}

import React, { useState } from 'react';
import { WebTool } from '../types';

interface WebToolManagerProps {
  webTools: WebTool[];
  setWebTools: React.Dispatch<React.SetStateAction<WebTool[]>>;
  onSelectTool: (tool: WebTool) => void;
}

const WebToolManager: React.FC<WebToolManagerProps> = ({ webTools, setWebTools, onSelectTool }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newTool, setNewTool] = useState<Omit<WebTool, 'id'>>({ 
    name: '', 
    url: '', 
    icon: '🔗', 
    openMode: 'iframe' 
  });

  const isHttps = window.location.protocol === 'https:';

  const addTool = () => {
    if (!newTool.name || !newTool.url) return;
    let finalUrl = newTool.url;
    if (!finalUrl.startsWith('http')) {
      finalUrl = 'https://' + finalUrl;
    }
    const tool: WebTool = {
      ...newTool,
      url: finalUrl,
      id: Date.now().toString()
    };
    setWebTools([...webTools, tool]);
    setNewTool({ name: '', url: '', icon: '🔗', openMode: 'iframe' });
    setIsAdding(false);
  };

  const removeTool = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setWebTools(webTools.filter(t => t.id !== id));
  };

  return (
    <div className="p-8 max-w-5xl mx-auto text-white">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-bold flex items-center">
            <span className="mr-2">🌐</span> Web Tool Dashboard
          </h2>
          <p className="text-sm text-white/40 mt-1">Integrate internal dashboards or dev utilities.</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded-lg transition-colors font-medium text-sm shadow-lg shadow-blue-900/20"
        >
          + Add New Tool
        </button>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {webTools.map((tool) => {
          const isMixedContent = isHttps && tool.url.startsWith('http:');
          const isExternal = tool.openMode === 'window';

          return (
            <div 
              key={tool.id}
              onClick={() => onSelectTool(tool)}
              className="group relative bg-white/5 border border-white/10 rounded-2xl p-6 cursor-pointer hover:bg-white/10 hover:border-white/30 hover:scale-[1.02] transition-all"
            >
              <button 
                onClick={(e) => removeTool(tool.id, e)}
                className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 p-2 text-white/20 hover:text-red-400 transition-all z-10"
              >
                ✕
              </button>
              <div className="flex justify-between items-start mb-4">
                <div className="text-4xl group-hover:scale-110 transition-transform origin-left">{tool.icon}</div>
                <div className="flex flex-col items-end space-y-1">
                  {isExternal ? (
                    <span className="text-[10px] bg-purple-500/20 text-purple-400 px-2 py-0.5 rounded border border-purple-500/30 font-bold">
                      EXTERNAL ↗
                    </span>
                  ) : (
                    <span className="text-[10px] bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded border border-blue-500/30 font-bold">
                      IFRAME
                    </span>
                  )}
                  {isMixedContent && !isExternal && (
                    <span className="text-[10px] bg-red-500/20 text-red-400 px-2 py-0.5 rounded border border-red-500/30 font-bold">
                      MIXED ERR
                    </span>
                  )}
                </div>
              </div>
              <div className="font-bold text-lg mb-1 truncate">{tool.name}</div>
              <div className="text-xs text-white/30 truncate font-mono">{tool.url}</div>
            </div>
          );
        })}

        {webTools.length === 0 && !isAdding && (
          <div className="col-span-full text-center py-24 bg-white/5 rounded-3xl border-2 border-dashed border-white/10">
            <div className="text-white/20 text-6xl mb-4">📦</div>
            <div className="text-white/40 font-medium">No tools registered</div>
          </div>
        )}
      </div>

      <div className="mt-12 p-8 bg-indigo-500/5 border border-indigo-500/10 rounded-3xl">
        <h4 className="text-indigo-400 text-sm font-bold flex items-center mb-4 uppercase tracking-widest">
          <span className="mr-2">💡</span> Best Practice for Intranet
        </h4>
        <div className="space-y-4 text-xs text-white/40 leading-relaxed">
          <p>
            <strong>The "Why":</strong> Browsers block <code>http://</code> inside <code>https://</code> for safety. 
            Also, many internal tools (like Jenkins, GitLab) explicitly forbid being displayed in an Iframe.
          </p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-black/20 p-4 rounded-xl">
              <p className="text-white/60 font-bold mb-1">✅ Recommended: independent Window</p>
              Use this for complex internal systems. It bypasses all Iframe security headers and Mixed Content errors.
            </div>
            <div className="bg-black/20 p-4 rounded-xl">
              <p className="text-white/60 font-bold mb-1">🚀 Advanced: Run Locally</p>
              Download this project and run <code>npm run dev</code>. Browsers allow <code>localhost</code> to embed almost anything.
            </div>
          </div>
        </div>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md flex items-center justify-center z-50 p-4">
          <div className="bg-slate-900 border border-white/20 rounded-3xl p-8 w-full max-w-md shadow-2xl">
            <h3 className="text-xl font-bold mb-6 flex items-center">
               <span className="mr-2">➕</span> Add Web Utility
            </h3>
            <div className="space-y-5">
              <div>
                <label className="block text-[10px] font-bold text-white/40 uppercase mb-1.5 tracking-widest">Display Name</label>
                <input 
                  type="text" 
                  value={newTool.name}
                  onChange={(e) => setNewTool({...newTool, name: e.target.value})}
                  className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-2.5 outline-none text-white focus:border-blue-500 transition-all"
                  placeholder="e.g. Jenkins Dashboard"
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-white/40 uppercase mb-1.5 tracking-widest">URL</label>
                <input 
                  type="text" 
                  value={newTool.url}
                  onChange={(e) => setNewTool({...newTool, url: e.target.value})}
                  className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-2.5 outline-none text-white focus:border-blue-500 transition-all font-mono text-sm"
                  placeholder="http://192.168.1.50:8080"
                />
              </div>

              <div className="bg-white/5 p-4 rounded-2xl border border-white/10">
                <label className="block text-[10px] font-bold text-white/40 uppercase mb-3 tracking-widest">Opening Strategy</label>
                <div className="grid grid-cols-2 gap-2">
                  <button 
                    onClick={() => setNewTool({...newTool, openMode: 'iframe'})}
                    className={`px-3 py-2 rounded-lg text-xs font-bold transition-all ${newTool.openMode === 'iframe' ? 'bg-blue-600 text-white' : 'bg-white/5 text-white/40'}`}
                  >
                    Internal Frame
                  </button>
                  <button 
                    onClick={() => setNewTool({...newTool, openMode: 'window'})}
                    className={`px-3 py-2 rounded-lg text-xs font-bold transition-all ${newTool.openMode === 'window' ? 'bg-purple-600 text-white' : 'bg-white/5 text-white/40'}`}
                  >
                    New Window
                  </button>
                </div>
                <p className="text-[10px] text-white/30 mt-3 italic">
                  {newTool.openMode === 'window' ? 'Best for intranet/local tools with security headers.' : 'Best for modern HTTPS-friendly sites.'}
                </p>
              </div>

              <div className="flex space-x-3 mt-8">
                <button onClick={() => setIsAdding(false)} className="flex-1 px-4 py-2.5 text-white/40 font-bold">Cancel</button>
                <button onClick={addTool} className="flex-1 px-4 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl font-bold shadow-lg shadow-blue-900/40 transition-all">Create</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

